#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Simple dynamic array for adjacency list
typedef struct {
    int *data;
    int size;
    int capacity;
} DynArr;

void initDynArr(DynArr *a, int cap) {
    a->data = (int *)malloc(cap * sizeof(int));
    a->size = 0;
    a->capacity = cap;
}

void pushDynArr(DynArr *a, int val) {
    if (a->size == a->capacity) {
        a->capacity = a->capacity * 2 + 1;
        a->data = (int *)realloc(a->data, a->capacity * sizeof(int));
    }
    a->data[a->size++] = val;
}

bool dfs(int v, DynArr *adj, bool *visited, bool *recStack) {
    visited[v] = true;
    recStack[v] = true;
    for (int i = 0; i < adj[v].size; ++i) {
        int nb = adj[v].data[i];
        if (!visited[nb]) {
            if (dfs(nb, adj, visited, recStack)) return true;
        } else if (recStack[nb]) {
            return true; // back edge -> cycle
        }
    }
    recStack[v] = false;
    return false;
}

bool hasDirectedCycle(int V, DynArr *adj) {
    bool *visited = (bool *)calloc(V, sizeof(bool));
    bool *recStack = (bool *)calloc(V, sizeof(bool));
    for (int i = 0; i < V; ++i) {
        if (!visited[i]) {
            if (dfs(i, adj, visited, recStack)) {
                free(visited);
                free(recStack);
                return true;
            }
        }
    }
    free(visited);
    free(recStack);
    return false;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int V, E; scanf("%d %d", &V, &E);
        DynArr *adj = (DynArr *)malloc(V * sizeof(DynArr));
        for (int i = 0; i < V; ++i) initDynArr(&adj[i], 2);
        for (int i = 0; i < E; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            pushDynArr(&adj[u], v);
        }
        if (hasDirectedCycle(V, adj)) printf("True\n");
        else printf("False\n");
        for (int i = 0; i < V; ++i) free(adj[i].data);
        free(adj);
    }
    return 0;
}

