bool dfs(int v, const vector<vector<int>>& adj, vector<char>& visited, vector<char>& recStack) {
    visited[v] = 1;
    recStack[v] = 1;
    for (int nb : adj[v]) {
        if (!visited[nb]) {
            if (dfs(nb, adj, visited, recStack)) return true;
        } else if (recStack[nb]) {
            return true;
        }
    }
    recStack[v] = 0;
    return false;
}

bool hasDirectedCycle(int V, const vector<vector<int>>& adj) {
    vector<char> visited(V, 0), recStack(V, 0);
    for (int i = 0; i < V; ++i) {
        if (!visited[i]) {
            if (dfs(i, adj, visited, recStack)) return true;
        }
    }
    return false;
}

