    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int V, E; cin >> V >> E;
        vector<vector<int>> adj(V);
        for (int i = 0; i < E; ++i) {
            int u, v; cin >> u >> v;
            adj[u].push_back(v);
        }
        cout << (hasDirectedCycle(V, adj) ? "True" : "False") << '\n';
    }
