import java.io.*;
import java.util.*;

public class Main {
    private static boolean dfs(int v, List<List<Integer>> adj, boolean[] visited, boolean[] recStack) {
        visited[v] = true;
        recStack[v] = true;
        for (int nb : adj.get(v)) {
            if (!visited[nb]) {
                if (dfs(nb, adj, visited, recStack)) return true;
            } else if (recStack[nb]) {
                return true;
            }
        }
        recStack[v] = false;
        return false;
    }

    private static boolean hasDirectedCycle(int V, List<List<Integer>> adj) {
        boolean[] visited = new boolean[V];
        boolean[] recStack = new boolean[V];
        for (int i = 0; i < V; ++i) {
            if (!visited[i]) {
                if (dfs(i, adj, visited, recStack)) return true;
            }
        }
        return false;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int V = Integer.parseInt(st.nextToken());
            int E = Integer.parseInt(st.nextToken());
            List<List<Integer>> adj = new ArrayList<>(V);
            for (int i = 0; i < V; ++i) adj.add(new ArrayList<>());
            for (int i = 0; i < E; ++i) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                adj.get(u).add(v);
            }
            sb.append(hasDirectedCycle(V, adj) ? "True" : "False").append('\n');
        }
        System.out.print(sb.toString());
    }
}

