import sys

def dfs(v, adj, visited, rec_stack):
    visited[v] = True
    rec_stack[v] = True
    for nb in adj[v]:
        if not visited[nb]:
            if dfs(nb, adj, visited, rec_stack):
                return True
        elif rec_stack[nb]:
            return True
    rec_stack[v] = False
    return False

def has_directed_cycle(V, adj):
    visited = [False] * V
    rec_stack = [False] * V
    for i in range(V):
        if not visited[i]:
            if dfs(i, adj, visited, rec_stack):
                return True
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        V = int(next(it)); E = int(next(it))
        adj = [[] for _ in range(V)]
        for _ in range(E):
            u = int(next(it)); v = int(next(it))
            adj[u].append(v)
        out_lines.append("True" if has_directed_cycle(V, adj) else "False")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

